import{DefaultLoadingManager,Mesh}from 'three';import{mergeGeometries}from 'three/addons/utils/BufferGeometryUtils.min.js';import Polyslice from 'https://cdn.jsdelivr.net/npm/@jgphilpott/polyslice@26.4.0/dist/index.browser.esm.js';class GcodeExporter{constructor(manager){this.manager=manager||DefaultLoadingManager}parse(scene,onDone,onError,options={}){this.parseAsync(scene,onDone,onError,options)}async parseAsync(scene,onDone,onError,options={}){if(typeof Polyslice==='undefined'){alert('Polyslice library failed to load.\n\nCheck your network connection.');if(typeof onError==='function'){onError('THREE.GCODEExporter: Polyslice library failed to load!');return null}else{throw new Error('THREE.GCODEExporter: Polyslice library failed to load!')}}const defaultOptions={printer:'Ender3',filament:'GenericPLA'};options=Object.assign(defaultOptions,options);const printer=new Polyslice.Printer(options.printer);const filament=new Polyslice.Filament(options.filament);const slicer=new Polyslice({printer:printer,filament:filament});const geometries=[];let mesh,mergedGeometry,gcode='',mesh_count=0;scene.updateMatrixWorld(true,true);try{scene.traverse((child)=>{if(child.isMesh&&child.geometry){const clonedGeom=child.geometry.clone();clonedGeom.applyMatrix4(child.matrixWorld);geometries.push(clonedGeom);mesh_count+=1}});if(geometries.length>1){mergedGeometry=await mergeGeometries(geometries);mesh=new Mesh(mergedGeometry);gcode=await slicer.slice(mesh)}else{gcode=await slicer.slice(scene)}}catch(err){if(onError){onError(err)}else{throw err}}if(mesh_count===0||gcode.trim().length===0){if(typeof onError==='function'){onError('THREE.GCODEExporter: No qualifying objects found or G-code generation failed!');return null}else{throw new Error('THREE.GCODEExporter: No qualifying objects found or G-code generation failed!')}}else{if(mesh){mergedGeometry.dispose();mesh.geometry.dispose();mesh.material.dispose();if(geometries.length>0){for(const geo of geometries){geo.dispose()}}}if(typeof onDone==='function'){onDone(gcode)}else{return gcode}}}}export{GcodeExporter};